// ============================================================
// context/AuthContext.jsx — Global Authentication State
// ============================================================
// React Context shares data across the entire app without
// passing props through every component level.
//
// AuthContext stores: current user, token, role, login/logout
// Any component can call: useAuth() to access this data.
// ============================================================

import React, { createContext, useContext, useState, useEffect } from "react";

// Create the context object
const AuthContext = createContext(null);

// ---- AuthProvider: wraps the whole app in App.js ----
export function AuthProvider({ children }) {
  // Initialize state from localStorage (survives page refresh)
  const [user,  setUser]  = useState(() => JSON.parse(localStorage.getItem("user")  || "null"));
  const [token, setToken] = useState(() => localStorage.getItem("token") || null);
  const [role,  setRole]  = useState(() => localStorage.getItem("role")  || null);

  /**
   * Call this after a successful login API response.
   * Stores user info, token, and role in both state + localStorage.
   */
  const login = (userData, accessToken, userRole) => {
    setUser(userData);
    setToken(accessToken);
    setRole(userRole);

    // Persist to localStorage so user stays logged in after refresh
    localStorage.setItem("user",  JSON.stringify(userData));
    localStorage.setItem("token", accessToken);
    localStorage.setItem("role",  userRole);
  };

  /**
   * Clear all auth state and redirect to login page.
   */
  const logout = () => {
    const redirectPath = role === "admin" ? "/admin/login" : "/login";
    setUser(null);
    setToken(null);
    setRole(null);
    localStorage.clear();
    window.location.href = redirectPath;
  };

  // Derived boolean: is the user currently authenticated?
  const isAuthenticated = !!token;
  const isAdmin         = role === "admin";
  const isMerchant      = role === "merchant";

  return (
    <AuthContext.Provider value={{ user, token, role, isAuthenticated, isAdmin, isMerchant, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

// ---- Custom hook for easy access ----
// Usage: const { user, logout } = useAuth();
export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) throw new Error("useAuth must be used inside <AuthProvider>");
  return context;
}
